INSERT INTO prp_master (id, program_name, description, frequency, responsible, category) VALUES (11, 'Calibration Program', 'Calibration of thermometers and measuring devices', 'Monthly', 'Manager', 'Manufacturing');
INSERT INTO prp_master (id, program_name, description, frequency, responsible, category) VALUES (12, 'Traceability and Recall Program', 'Product traceability and recall procedures', 'As needed', 'Manager', 'Manufacturing');
INSERT INTO prp_master (id, program_name, description, frequency, responsible, category) VALUES (13, 'Document Control Program', 'Control and management of food safety documents', 'Monthly', 'Manager', 'System');
INSERT INTO prp_master (id, program_name, description, frequency, responsible, category) VALUES (14, 'Record Keeping Program', 'Management and storage of food safety records', 'Daily', 'Staff', 'System');
