INSERT INTO sop_master (id, sop_name, process_step, purpose, scope, procedure_text, frequency, responsible, related_prp) VALUES (1, 'Receiving Inspection Procedure', 'Receiving', 'Ensure all incoming materials meet safety standards', 'All incoming food and materials', '1. Check supplier approval 2. Inspect packaging 3. Check temperature if required 4. Accept or reject materials', 'Each Delivery', 'Staff', 'Supplier Control Program');
INSERT INTO sop_master (id, sop_name, process_step, purpose, scope, procedure_text, frequency, responsible, related_prp) VALUES (2, 'Cold Storage Procedure', 'Cold Holding', 'Maintain safe storage temperature', 'All refrigerated storage', '1. Store food below 5°C 2. Monitor temperature 3. Record readings 4. Report deviations', 'Hourly', 'Staff', 'Temperature Control Program');
INSERT INTO sop_master (id, sop_name, process_step, purpose, scope, procedure_text, frequency, responsible, related_prp) VALUES (3, 'Hot Holding Procedure', 'Hot Holding', 'Keep food at safe hot holding temperature', 'All hot holding equipment', '1. Maintain temperature above 60°C 2. Monitor regularly 3. Record temperature', 'Hourly', 'Staff', 'Temperature Control Program');
INSERT INTO sop_master (id, sop_name, process_step, purpose, scope, procedure_text, frequency, responsible, related_prp) VALUES (4, 'Cooking Temperature Control Procedure', 'Cooking / Baking', 'Ensure food is cooked safely', 'All cooking processes', '1. Cook food to at least 75°C 2. Measure temperature 3. Record results', 'Each batch', 'Staff', 'Process Control Program');
INSERT INTO sop_master (id, sop_name, process_step, purpose, scope, procedure_text, frequency, responsible, related_prp) VALUES (5, 'Cooling Procedure', 'Cooling', 'Ensure safe cooling of cooked food', 'All cooling processes', '1. Cool food from 60°C to 5°C within 6 hours 2. Monitor time and temperature', 'Each batch', 'Staff', 'Process Control Program');
INSERT INTO sop_master (id, sop_name, process_step, purpose, scope, procedure_text, frequency, responsible, related_prp) VALUES (6, 'Reheating Procedure', 'Reheating', 'Ensure safe reheating of food', 'All reheating processes', '1. Reheat food to at least 75°C 2. Record temperature', 'Each batch', 'Staff', 'Process Control Program');
INSERT INTO sop_master (id, sop_name, process_step, purpose, scope, procedure_text, frequency, responsible, related_prp) VALUES (7, 'Cleaning and Sanitation Procedure', 'Preparation', 'Maintain cleanliness of equipment and surfaces', 'All food contact surfaces', '1. Remove debris 2. Wash with detergent 3. Rinse 4. Sanitize 5. Air dry', 'Daily', 'Staff', 'Cleaning and Sanitation Program');
INSERT INTO sop_master (id, sop_name, process_step, purpose, scope, procedure_text, frequency, responsible, related_prp) VALUES (8, 'Personal Hygiene Procedure', 'Preparation', 'Ensure staff hygiene compliance', 'All staff handling food', '1. Wash hands regularly 2. Wear clean uniform 3. Use gloves when required', 'Daily', 'Staff', 'Personal Hygiene Program');
INSERT INTO sop_master (id, sop_name, process_step, purpose, scope, procedure_text, frequency, responsible, related_prp) VALUES (9, 'Pest Control Procedure', 'Storage', 'Prevent pest contamination', 'All facility areas', '1. Inspect facility 2. Use traps 3. Record pest activity', 'Weekly', 'Manager', 'Pest Control Program');
INSERT INTO sop_master (id, sop_name, process_step, purpose, scope, procedure_text, frequency, responsible, related_prp) VALUES (10, 'Waste Management Procedure', 'General', 'Ensure proper waste handling', 'All waste areas', '1. Separate waste 2. Dispose daily 3. Clean bins', 'Daily', 'Staff', 'Waste Management Program');
INSERT INTO sop_master (id, sop_name, process_step, purpose, scope, procedure_text, frequency, responsible, related_prp) VALUES (11, 'Equipment Maintenance Procedure', 'General', 'Maintain equipment in good condition', 'All equipment', '1. Perform scheduled maintenance 2. Report faults', 'Monthly', 'Manager', 'Equipment Maintenance Program');
INSERT INTO sop_master (id, sop_name, process_step, purpose, scope, procedure_text, frequency, responsible, related_prp) VALUES (12, 'Allergen Control Procedure', 'Preparation', 'Prevent allergen cross contact', 'All food preparation areas', '1. Separate allergen materials 2. Clean equipment 3. Label properly', 'Daily', 'Staff', 'Allergen Control Program');
INSERT INTO sop_master (id, sop_name, process_step, purpose, scope, procedure_text, frequency, responsible, related_prp) VALUES (13, 'Internal Audit Procedure', 'General', 'Verify food safety system compliance', 'All processes', '1. Conduct audit 2. Record findings 3. Take corrective action', 'Monthly', 'Manager', 'Internal Audit Program');
INSERT INTO sop_master (id, sop_name, process_step, purpose, scope, procedure_text, frequency, responsible, related_prp) VALUES (14, 'Training Procedure', 'General', 'Ensure staff are trained in food safety', 'All staff', '1. Conduct training sessions 2. Record attendance', 'As needed', 'Manager', 'Training Program');
INSERT INTO sop_master (id, sop_name, process_step, purpose, scope, procedure_text, frequency, responsible, related_prp) VALUES (15, 'Document Control Procedure', 'General', 'Control all food safety documents', 'All documents', '1. Approve documents 2. Update regularly 3. Archive old versions', 'Monthly', 'Manager', 'Document Control Program');
INSERT INTO sop_master (id, sop_name, process_step, purpose, scope, procedure_text, frequency, responsible, related_prp) VALUES (16, 'Record Keeping Procedure', 'General', 'Maintain proper records', 'All logs and records', '1. Record data accurately 2. Store records securely', 'Daily', 'Staff', 'Record Keeping Program');
INSERT INTO sop_master (id, sop_name, process_step, purpose, scope, procedure_text, frequency, responsible, related_prp) VALUES (17, 'Pasteurization Procedure', 'Processing', 'Ensure safe pasteurization process', 'Dairy and beverage processing', '1. Heat to required temperature 2. Maintain time 3. Record parameters', 'Each batch', 'Staff', 'Process Control Program');
INSERT INTO sop_master (id, sop_name, process_step, purpose, scope, procedure_text, frequency, responsible, related_prp) VALUES (18, 'Fermentation Control Procedure', 'Processing', 'Control fermentation process', 'Dairy and beverage products', '1. Monitor pH 2. Control time 3. Record results', 'Each batch', 'Staff', 'Process Control Program');
INSERT INTO sop_master (id, sop_name, process_step, purpose, scope, procedure_text, frequency, responsible, related_prp) VALUES (19, 'Meat Processing Hygiene Procedure', 'Preparation', 'Ensure hygienic meat processing', 'Meat processing areas', '1. Clean surfaces 2. Avoid cross contamination 3. Maintain hygiene', 'Each batch', 'Staff', 'Process Control Program');
INSERT INTO sop_master (id, sop_name, process_step, purpose, scope, procedure_text, frequency, responsible, related_prp) VALUES (20, 'Chilling Procedure', 'Cooling', 'Ensure proper chilling of products', 'Meat and processed food', '1. Rapidly cool products 2. Monitor temperature 3. Record results', 'Each batch', 'Staff', 'Process Control Program');
INSERT INTO sop_master (id, sop_name, process_step, purpose, scope, procedure_text, frequency, responsible, related_prp) VALUES (21, 'Freezing Procedure', 'Cold Holding', 'Ensure proper freezing conditions', 'Frozen products', '1. Maintain freezing temperature 2. Monitor and record', 'Each batch', 'Staff', 'Process Control Program');
INSERT INTO sop_master (id, sop_name, process_step, purpose, scope, procedure_text, frequency, responsible, related_prp) VALUES (22, 'Water Quality Control Procedure', 'Processing', 'Ensure water safety', 'Water and beverage systems', '1. Test water quality 2. Monitor parameters 3. Record results', 'Daily', 'Manager', 'Water Quality Control Program');
INSERT INTO sop_master (id, sop_name, process_step, purpose, scope, procedure_text, frequency, responsible, related_prp) VALUES (23, 'Calibration Procedure', 'General', 'Ensure accuracy of measuring devices', 'All measuring equipment', '1. Calibrate regularly 2. Record calibration results', 'Monthly', 'Manager', 'Calibration Program');
INSERT INTO sop_master (id, sop_name, process_step, purpose, scope, procedure_text, frequency, responsible, related_prp) VALUES (24, 'Traceability and Recall Procedure', 'General', 'Ensure product traceability and recall capability', 'All products', '1. Assign batch codes 2. Track products 3. Recall if needed', 'As needed', 'Manager', 'Traceability and Recall Program');
INSERT INTO fsms_documents (id, document_name, description, responsible) VALUES (1, 'Food Safety Policy', 'The organization is committed to producing safe food by implementing HACCP principles, maintaining hygiene standards, and complying with food safety regulations', 'Owner');
INSERT INTO fsms_documents (id, document_name, description, responsible) VALUES (2, 'Food Safety Objectives', 'The organization aims to maintain safe food production, monitor critical control points, and continuously improve food safety performance', 'Owner');
INSERT INTO fsms_documents (id, document_name, description, responsible) VALUES (3, 'HACCP Team', 'The HACCP team is responsible for developing, implementing, and maintaining the HACCP system within the organization', 'Manager');
INSERT INTO fsms_documents (id, document_name, description, responsible) VALUES (4, 'Product Description', 'Description of food products including ingredients, storage conditions, and shelf life', 'Manager');
INSERT INTO fsms_documents (id, document_name, description, responsible) VALUES (5, 'Intended Use', 'Description of how the food product is expected to be used by consumers', 'Manager');
INSERT INTO fsms_documents (id, document_name, description, responsible) VALUES (6, 'Flow Diagram Verification', 'Procedure for verifying that the process flow diagram accurately represents the food preparation process', 'Manager');
INSERT INTO fsms_documents (id, document_name, description, responsible) VALUES (7, 'HACCP Verification Procedure', 'Procedures used to verify that the HACCP system is working effectively', 'Manager');
INSERT INTO fsms_documents (id, document_name, description, responsible) VALUES (8, 'Record Keeping Procedure', 'Procedure for maintaining and storing food safety records and monitoring logs', 'Manager');
INSERT INTO fsms_documents (id, document_name, description, responsible) VALUES (9, 'Corrective Action Procedure', 'Steps taken when monitoring results indicate a deviation from critical limits', 'Manager');
INSERT INTO fsms_documents (id, document_name, description, responsible) VALUES (10, 'Internal Audit Procedure', 'Procedure for conducting internal food safety audits within the organization', 'Manager');
INSERT INTO fsms_documents (id, document_name, description, responsible) VALUES (11, 'Product Recall Procedure', 'Procedure for identifying, tracing, and removing unsafe or non-compliant food products from sale or distribution. The organization will immediately stop using the affected product, isolate the batch, inform management, and take corrective actions to protect consumer safety. Records of the recall and actions taken will be maintained.', 'Manager');
INSERT INTO fsms_documents (id, document_name, description, responsible) VALUES (12, 'Supplier Approval Procedure', 'Procedure for evaluating, approving, and monitoring suppliers to ensure raw material safety and compliance', 'QA Manager');
INSERT INTO fsms_documents (id, document_name, description, responsible) VALUES (13, 'Approved Supplier List', 'List of approved suppliers who meet food safety and quality requirements', 'QA Manager');
INSERT INTO fsms_documents (id, document_name, description, responsible) VALUES (14, 'Raw Material Specification', 'Specifications for raw materials including safety, quality, and acceptance criteria', 'QA Manager');
INSERT INTO fsms_documents (id, document_name, description, responsible) VALUES (15, 'Traceability Procedure', 'Procedure for tracking raw materials and finished products through all stages of production', 'QA Manager');
INSERT INTO fsms_documents (id, document_name, description, responsible) VALUES (16, 'Batch Coding System', 'System for assigning batch numbers to products for identification and traceability', 'Production Manager');
INSERT INTO fsms_documents (id, document_name, description, responsible) VALUES (17, 'Product Identification Procedure', 'Procedure for labeling and identifying products throughout production and distribution', 'Production Manager');
INSERT INTO fsms_documents (id, document_name, description, responsible) VALUES (18, 'Allergen Control Procedure', 'Procedure for identifying, managing, and preventing allergen cross-contact', 'QA Manager');
INSERT INTO fsms_documents (id, document_name, description, responsible) VALUES (19, 'Allergen Risk Assessment', 'Assessment of allergen risks associated with raw materials and processing steps', 'QA Manager');
INSERT INTO fsms_documents (id, document_name, description, responsible) VALUES (20, 'Allergen Cleaning Validation', 'Procedure for validating cleaning effectiveness to remove allergen residues', 'QA Manager');
INSERT INTO fsms_documents (id, document_name, description, responsible) VALUES (21, 'Calibration Procedure', 'Procedure for calibrating equipment such as thermometers, pH meters, and sensors', 'Maintenance Manager');
INSERT INTO fsms_documents (id, document_name, description, responsible) VALUES (22, 'Calibration Records Template', 'Template for recording calibration results and maintaining equipment accuracy', 'Maintenance Manager');
INSERT INTO fsms_documents (id, document_name, description, responsible) VALUES (23, 'Equipment Verification Procedure', 'Procedure to verify equipment performance and functionality before use', 'Maintenance Manager');
INSERT INTO fsms_documents (id, document_name, description, responsible) VALUES (24, 'Preventive Maintenance Procedure', 'Procedure for scheduled maintenance to ensure equipment reliability', 'Maintenance Manager');
INSERT INTO fsms_documents (id, document_name, description, responsible) VALUES (25, 'Equipment Maintenance Log', 'Log for recording maintenance activities and equipment repairs', 'Maintenance Manager');
INSERT INTO fsms_documents (id, document_name, description, responsible) VALUES (26, 'Breakdown Handling Procedure', 'Procedure for managing equipment breakdowns and minimizing production risks', 'Maintenance Manager');
INSERT INTO fsms_documents (id, document_name, description, responsible) VALUES (27, 'Cleaning and Sanitation Procedure', 'Procedure for cleaning and sanitizing equipment and facilities', 'QA Manager');
INSERT INTO fsms_documents (id, document_name, description, responsible) VALUES (28, 'Cleaning Schedule', 'Schedule for routine cleaning and sanitation activities', 'Production Manager');
INSERT INTO fsms_documents (id, document_name, description, responsible) VALUES (29, 'Chemical Control Procedure', 'Procedure for handling, storing, and using cleaning chemicals safely', 'QA Manager');
INSERT INTO fsms_documents (id, document_name, description, responsible) VALUES (30, 'Pest Control Procedure', 'Procedure for monitoring and controlling pests within the facility', 'QA Manager');
INSERT INTO fsms_documents (id, document_name, description, responsible) VALUES (31, 'Pest Monitoring Records', 'Records of pest control inspections and corrective actions', 'QA Manager');
INSERT INTO fsms_documents (id, document_name, description, responsible) VALUES (32, 'Training Procedure', 'Procedure for training staff on food safety and operational practices', 'HR / Training Officer');
INSERT INTO fsms_documents (id, document_name, description, responsible) VALUES (33, 'Competency Assessment', 'Procedure for evaluating staff competence and performance', 'HR / Training Officer');
INSERT INTO fsms_documents (id, document_name, description, responsible) VALUES (34, 'Training Plan', 'Planned schedule of training activities for employees', 'HR / Training Officer');
INSERT INTO fsms_documents (id, document_name, description, responsible) VALUES (35, 'Non-Conformance Procedure', 'Procedure for identifying and managing non-conforming products or processes', 'QA Manager');
INSERT INTO fsms_documents (id, document_name, description, responsible) VALUES (36, 'Product Hold & Release Procedure', 'Procedure for holding and releasing products based on quality and safety checks', 'QA Manager');
INSERT INTO fsms_documents (id, document_name, description, responsible) VALUES (37, 'Document Control Procedure', 'Procedure for managing and updating documents within the system', 'QA Manager');
INSERT INTO fsms_documents (id, document_name, description, responsible) VALUES (38, 'Record Control Procedure', 'Procedure for maintaining and storing records securely and effectively', 'QA Manager');
INSERT INTO fsms_documents (id, document_name, description, responsible) VALUES (39, 'Risk Assessment Procedure', 'Procedure for assessing risks related to food safety hazards', 'QA Manager');
INSERT INTO fsms_documents (id, document_name, description, responsible) VALUES (40, 'Hazard Evaluation Methodology', 'Methodology used to evaluate hazards based on severity and likelihood', 'QA Manager');
